// UpscaleImageRequest Upscale or enhance an image based on the supplied parameters. Using a scale of 1 with enhance enabled will only run the enhancer.
type UpscaleImageRequest struct {
	// Enhance Whether to enhance the image using Venice's image engine during upscaling. Must be true if scale is 1.
	Enhance *UpscaleImageRequest_Enhance `json:"enhance,omitempty"`

	// EnhanceCreativity Higher values let the enhancement AI change the image more. Setting this to 1 effectively creates an entirely new image.
	EnhanceCreativity *float32 `json:"enhanceCreativity,omitempty"`

	// EnhancePrompt The text to image style to apply during prompt enhancement. Does best with short descriptive prompts, like gold, marble or angry, menacing.
	EnhancePrompt *string `json:"enhancePrompt,omitempty"`

	// Image The image to upscale. Can be either a file upload or a base64-encoded string. Image dimensions must be at least 65536 pixels and final dimensions after scaling must not exceed 16777216 pixels. File size must be less than 25MB.
	Image UpscaleImageRequest_Image `json:"image"`

	// Replication How strongly lines and noise in the base image are preserved. Higher values are noisier but less plastic/AI "generated"/hallucinated. Must be between 0 and 1.
	Replication *float32 `json:"replication,omitempty"`

	// Scale The scale factor for upscaling the image. Must be a number between 1 and 4. Scale of 1 requires enhance to be set true and will only run the enhancer. Scale must be > 1 if enhance is false. A scale of 4 with large images will result in the scale being dynamically set to ensure the final image stays within the maximum size limits.
	Scale *float32 `json:"scale,omitempty"`
}

